const items = $input.all();
const rawJson = items[0].json;
const chatId = String(
  rawJson?.message?.chat?.id ||
  rawJson?.callback_query?.message?.chat?.id
);
const staticData = $getWorkflowStaticData('global');
const incomingText = rawJson?.message?.text || '';

// Initialise if first time
if (!staticData[chatId]) {
  staticData[chatId] = { state: 'idle', data: {}, qaHistory: [] };
}

// Commands always take priority regardless of current state
if (incomingText === '/start' || incomingText === '/log') {
  staticData[chatId] = { state: 'idle', data: {}, qaHistory: [] };
} else if (incomingText === '/insights') {
  staticData[chatId].state = 'insights_requested';
} else if (incomingText === '/qa') {
  staticData[chatId].state = 'qa_requested';
} else if (incomingText.startsWith('/schedule')) {
  staticData[chatId].state = 'schedule_requested';
  staticData[chatId].scheduleInput = incomingText.replace('/schedule', '').trim();
} else if (incomingText === '/dashboard') {
  staticData[chatId].state = 'dashboard_requested';
}

const sessionState = staticData[chatId].state;
const sessionData = staticData[chatId].data || {};
const qaHistory = staticData[chatId].qaHistory || [];

return [{
  json: {
    chatId: chatId,
    sessionState: sessionState,
    sessionData: sessionData,
    qaHistory: qaHistory,
    userMessage: incomingText,
    scheduleInput: staticData[chatId].scheduleInput || '',
    originalData: rawJson
  }
}];

