    buttonType: "none"
  },
  ask_conditions: {
    text: "🌤 What were the conditions like?",
    buttonType: "conditions"
  },
  ask_warmup: {
    text: "🔥 Did you warm up properly?",
    buttonType: "yes_no"
  },
  ask_tactical_focus: {
    text: "🧠 What was your tactical focus today?",
    buttonType: "none"
  },
  ask_drills_focus: {
    text: "🎯 What did you focus on during the session?",
    buttonType: "none"
  },
  ask_serve: {
    text: "🎾 Let's rate your skills today (1–5, or N/A)\n\nServe?",
    buttonType: "rating"
  },
  ask_return: {
    text: 'Return?',
    buttonType: 'rating'
  },
  ask_forehand: {
