    buttonType: "rating"
  },
  ask_backhand: {
    text: "Backhand?",
    buttonType: "rating"
  },
  ask_volley: {
    text: "Volley?",
    buttonType: "rating"
  },
  ask_footwork: {
    text: "Footwork?",
    buttonType: "rating"
  },
  ask_focus: {
    text: "Mental focus?",
    buttonType: "rating"
  },
  ask_energy_before: {
    text: "⚡ Energy level BEFORE the session?",
    buttonType: "energy"
  },
  ask_energy_after: {
    text: "⚡ Energy level AFTER the session?",
    buttonType: "energy"
  },
  ask_discomfort: {
