    buttonType: "yes_no"
  },
  ask_discomfort_detail: {
    text: "Describe the discomfort — where and what did it feel like?",
    buttonType: "none"
  },
  ask_mood: {
    text: "💬 How would you describe today's session?",
    buttonType: "none"
  },
  ask_went_well: {
    text: "✅ What went well today?",
    buttonType: "skip"
  },
  ask_improve: {
    text: "📈 What do you want to improve?",
    buttonType: "skip"
  },
  ask_notes: {
  text: "📝 Any additional notes about today's session?",
  buttonType: "skip"
},
  summary: {
    text: "summary",
    buttonType: "summary"
  }
};

const question = questions[nextState];

// Override duration question text if previous input was invalid
if (nextState === 'ask_duration' && input.durationError) {
  question.text = "⚠️ Please enter numbers only (e.g. 90 for 90 minutes). How long was the session?";
}

if (!question) {
  return [{
    json: {
      chatId: chatId,
      text: "Something went wrong. Type /start to begin again.",
      buttonType: "none",
      hasButtons: false
    }
  }];
}

const hasButtons = question.buttonType !== "none";

return [{
  json: {
    chatId: chatId,
    text: question.text,
    buttonType: question.buttonType,
    hasButtons: hasButtons,
    nextState: nextState
  }
}];

