// Apply escaping to all free-text fields
const cleanData = {
  ...data,
  format: esc(data.format),
  location: esc(data.location),
  conditions: esc(data.conditions),
  warmup: esc(data.warmup),
  drills_focus: esc(data.drills_focus),
  discomfort: esc(data.discomfort),
  discomfort_detail: esc(data.discomfort_detail),
  mood: esc(data.mood),
  went_well: esc(data.went_well),
  improve: esc(data.improve),
  notes: esc(data.notes),
  opponent_name: esc(data.opponent_name),
  tactical_focus: esc(data.tactical_focus),
  score: esc(data.score),
  result: esc(data.result),
  opponent_level: esc(data.opponent_level),
  return_rating: data.return_rating !== undefined ? data.return_rating : null
};

// Generate unique IDs
const sessionId = 'sess_' + Date.now() + '_' + chatId;
const matchId = 'match_' + Date.now() + '_' + chatId;

// Today's date
const today = new Date().toISOString().split('T')[0];
const now = new Date().toISOString();

// Reset state
staticData[chatId] = { state: 'idle', data: {} };

return [{
  json: {
    chatId: chatId,
    sessionId: sessionId,
    matchId: matchId,
    today: today,
    now: now,
    data: cleanData
  }
}];

