const input = $input.all()[0].json;
const chatId = input.chatId;

// Calculate date range — last 90 days
const now = new Date();
const today = now.toISOString().split('T')[0];

const ninetyDaysAgo = new Date();
ninetyDaysAgo.setDate(now.getDate() - 90);
const startDate = ninetyDaysAgo.toISOString().split('T')[0];

// Also calculate 30-day cutoffs for trend comparison
const thirtyDaysAgo = new Date();
thirtyDaysAgo.setDate(now.getDate() - 30);
const midDate = thirtyDaysAgo.toISOString().split('T')[0];

const sixtyDaysAgo = new Date();
sixtyDaysAgo.setDate(now.getDate() - 60);
const earlyDate = sixtyDaysAgo.toISOString().split('T')[0];

return [{
  json: {
    chatId: chatId,
    today: today,
    startDate: startDate,   // 90 days ago
    midDate: midDate,        // 30 days ago (for improvement trajectory)
    earlyDate: earlyDate     // 60 days ago (for first 30-day window)
  }
}];

const staticData = $getWorkflowStaticData('global');
const chatId = $input.all()[0].json.chatId;
const data = $input.all()[0].json.sessionData;

const escape = (s) => {
  if (s === null || s === undefined) return 'N/A';
  return String(s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
};

const capitalize = (s) => {
  if (!s) return 'N/A';
  return s.charAt(0).toUpperCase() + s.slice(1);
};

const val = (v) => escape(v);

let lines = [];

lines.push('📋 <b>Session Summary</b>');
lines.push('');
lines.push(`🎾 <b>Type:</b> ${capitalize(escape(data.session_type).replace(/_/g, ' '))}`);
lines.push(`🏸 <b>Format:</b> ${capitalize(escape(data.format))}`);
lines.push(`📍 <b>Location:</b> ${val(data.location)}`);
lines.push(`⏱ <b>Duration:</b> ${val(data.duration)} min`);
lines.push(`🌤 <b>Conditions:</b> ${capitalize(escape(data.conditions))}`);
lines.push(`🔥 <b>Warm up:</b> ${capitalize(escape(data.warmup))}`);

if (data.drills_focus) {
  lines.push(`🎯 <b>Drills focus:</b> ${val(data.drills_focus)}`);
}

if (data.session_type === 'match') {
  lines.push('');
  lines.push('🏆 <b>Match Details</b>');
  lines.push(`👤 <b>Opponent:</b> ${val(data.opponent_name)}`);
  lines.push(`💪 <b>Their Level:</b> ${capitalize(escape(data.opponent_level))}`);
  lines.push(`📊 <b>Score:</b> ${val(data.score)}`);
  lines.push(`🏅 <b>Result:</b> ${capitalize(escape(data.result))}`);
  lines.push(`🧠 <b>Tactical focus:</b> ${val(data.tactical_focus)}`);
}

lines.push('');
lines.push('🎯 <b>Skill Ratings</b>');
lines.push(`Serve: ${val(data.serve)} | Forehand: ${val(data.forehand)} | Backhand: ${val(data.backhand)}`);
if (data.session_type === 'match' || data.session_type === 'social_game') {
  lines.push(`Return: ${val(data.return_rating)} | Volley: ${val(data.volley)} | Footwork: ${val(data.footwork)} | Focus: ${val(data.focus)}`);
} else {
  lines.push(`Volley: ${val(data.volley)} | Footwork: ${val(data.footwork)} | Focus: ${val(data.focus)}`);
}

lines.push('');
lines.push('⚡ <b>Energy</b>');
lines.push(`Before: ${val(data.energy_before)} | After: ${val(data.energy_after)}`);

lines.push('');
lines.push(`🩹 <b>Discomfort:</b> ${capitalize(escape(data.discomfort))}${data.discomfort_detail ? ' — ' + escape(data.discomfort_detail) : ''}`);
lines.push(`💬 <b>Mood:</b> ${val(data.mood)}`);
lines.push(`✅ <b>Went well:</b> ${val(data.went_well)}`);
lines.push(`📈 <b>Improve:</b> ${val(data.improve)}`);
lines.push(`📝 <b>Notes:</b> ${val(data.notes)}`);

lines.push('');
lines.push('<i>Does everything look correct?</i>');

staticData[chatId].state = 'confirm_save';

return [{
  json: {
    chatId: chatId,
    text: lines.join('\n'),
    sessionData: data
  }
}];

// Get data from both query nodes
const sessionItems = $('Query SESSION').all();
const matchItems = $('Query MATCH_RESULT').all();
const handleInsights = $('Handle Insights').first().json;

// Deduplicate sessions
const allSessionItems = sessionItems.map(item => item.json);
const seenSessions = new Set();
const sessions = allSessionItems.filter(s => {
  if (seenSessions.has(s.session_id)) return false;
  seenSessions.add(s.session_id);
  return true;
});

// Deduplicate matches
const allMatchItems = matchItems.map(item => item.json);
const seen = new Set();
const matches = allMatchItems.filter(m => {
  if (seen.has(m.match_id)) return false;
  seen.add(m.match_id);
  return true;
});

const chatId = handleInsights.chatId;
const midDate = handleInsights.midDate;     // 30 days ago
const earlyDate = handleInsights.earlyDate; // 60 days ago

// ── Helper ──────────────────────────────────────────────
const avg = arr => {
  const nums = arr.map(v => parseFloat(v)).filter(v => !isNaN(v));
