parameters.jsCode:
const staticData = $getWorkflowStaticData('global');
const chatId = $('Extract Schedule JSON').first().json.chatId;
staticData[chatId] = { state: 'idle' };
return [{ json: { success: true } }];

const event = $('IF Session Tomorrow?').first().json;
const allItems = $('Query Last Session (Pre-Session)').all();

// Separate last 3 sessions and last match
const lastSessionItems = allItems.filter(item => item.json.record_type === 'last_session').map(i => i.json);
const lastMatchItem = allItems.find(item => item.json.record_type === 'last_match')?.json || {};

// Format event details with MYT timezone fix
const eventTitle = event.summary || 'Tennis Session';
const eventStart = new Date(event.start.dateTime || event.start.date);
const eventDate = eventStart.toLocaleDateString('en-MY', {
  weekday: 'long', day: 'numeric', month: 'long',
  timeZone: 'Asia/Kuala_Lumpur'
});
const eventTime = eventStart.toLocaleTimeString('en-MY', {
  hour: '2-digit', minute: '2-digit',
  timeZone: 'Asia/Kuala_Lumpur'
});
const eventLocation = event.location || 'Unknown location';

// Extract weather for session time
const weather = $('Query Weather Forecast').first().json;

// eventStart is already parsed — get MYT hour directly from the string
const sessionDateStr = eventStart.toLocaleDateString('en-CA', { timeZone: 'Asia/Kuala_Lumpur' });
const sessionHour = parseInt(eventStart.toLocaleTimeString('en-MY', { 
  hour: '2-digit', 
  hour12: false,
  timeZone: 'Asia/Kuala_Lumpur' 
}).split(':')[0]);

// Find matching hour in forecast — times are already in MYT
const hourIndex = weather.hourly.time.findIndex(t => {
  const tDate = t.split('T')[0];
  const tHour = parseInt(t.split('T')[1].split(':')[0]);
  return tDate === sessionDateStr && tHour === sessionHour;
});

let weatherContext = '';
if (hourIndex !== -1) {
  const temp = weather.hourly.temperature_2m[hourIndex];
  const rain = weather.hourly.precipitation_probability[hourIndex];
  const wind = weather.hourly.windspeed_10m[hourIndex];
  const uv = weather.hourly.uv_index[hourIndex];
  weatherContext = `Weather forecast at session time (${sessionHour}:00 MYT):
- Temperature: ${temp}°C
- Rain probability: ${rain}%
- Wind speed: ${wind} km/h
- UV index: ${uv}`;
} else {
  weatherContext = `Weather forecast: data not available for session time (hour ${sessionHour})`;
}

// Detect session type from calendar title
const titleLower = eventTitle.toLowerCase();
let sessionType = 'session';
if (titleLower.includes('match')) sessionType = 'match';
else if (titleLower.includes('coaching')) sessionType = 'coaching';
else if (titleLower.includes('social')) sessionType = 'social game';
else if (titleLower.includes('solo') || titleLower.includes('drill')) sessionType = 'solo drill';

// Aggregate last 3 sessions
const avgField = (field) => {
  const vals = lastSessionItems.map(s => parseFloat(s[field])).filter(v => !isNaN(v));
  return vals.length ? (vals.reduce((a, b) => a + b, 0) / vals.length).toFixed(1) : 'N/A';
};

const lastDate = lastSessionItems[0]?.session_date || 'N/A';
const lastType = lastSessionItems[0]?.session_type
  ? lastSessionItems[0].session_type.split('_').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ')
  : 'N/A';

const sanitize = (str) => {
  if (!str || str === 'N/A') return 'N/A';
  return String(str).replace(/[\u0000-\u001F\u007F]/g, ' ').trim();
};
const commonImprove = lastSessionItems.map(s => sanitize(s.improve)).filter(v => v && v !== 'N/A').join('; ') || 'N/A';
const commonWentWell = lastSessionItems.map(s => sanitize(s.went_well)).filter(v => v && v !== 'N/A').join('; ') || 'N/A';
const commonNotes = lastSessionItems.map(s => sanitize(s.notes)).filter(v => v && v !== 'N/A').join('; ') || 'N/A';

const serve = avgField('serve');
const returnRating = avgField('return_rating');
const forehand = avgField('forehand');
const backhand = avgField('backhand');
const volley = avgField('volley');
const footwork = avgField('footwork');
const focus = avgField('mental_focus');

// Last match details
const lastMatchDate = lastMatchItem.session_date || null;
const lastMatchOpponent = lastMatchItem.opponent_name || null;
const lastMatchResult = lastMatchItem.result || null;
const lastMatchScore = lastMatchItem.score || null;
const lastMatchTactical = lastMatchItem.tactical_focus || null;
const lastMatchWentWell = lastMatchItem.went_well || null;
const lastMatchImprove = lastMatchItem.improve || null;

// Build last match context string
let lastMatchContext = '';
if (lastMatchDate) {
  lastMatchContext = `Last match (${lastMatchDate}):
- Opponent: ${sanitize(lastMatchOpponent) || 'Unknown'}
- Result: ${lastMatchResult || 'N/A'} ${lastMatchScore ? '(' + lastMatchScore + ')' : ''}
- Tactical focus: ${sanitize(lastMatchTactical) || 'N/A'}
- Went well: ${sanitize(lastMatchWentWell) || 'N/A'}
- Needs improvement: ${sanitize(lastMatchImprove) || 'N/A'}`;
}

// Build session-type specific instructions
let sessionTypeInstructions = '';
if (sessionType === 'match') {
  sessionTypeInstructions = `This is a MATCH. Include:
1. A reminder of the match details (opponent if mentioned in the event title, location, time)
2. One key focus area based on the weakest skill or common improvement themes across recent sessions
3. A mental cue or game plan tip informed by the last match context if available
4. Add a section with header exactly "Weather Forecast" — always include this section. Mention the temperature, rain probability percentage, and UV index. If rain probability is above 40%, warn the player to have a backup plan or arrive early. If temperature is above 32°C, add a hydration tip. If UV index is above 6, remind them to apply sunscreen.
5. End with a natural, energetic closing statement like a coach sending their player off — no label, no header`;
} else if (sessionType === 'coaching') {
  sessionTypeInstructions = `This is a COACHING session. Include:
1. A reminder of the session details
2. One or two specific goals to bring up with the coach based on common improvement themes
3. A quick physical warm-up tip
4. Add a section with header exactly "Weather Forecast" — always include this section. Mention the temperature, rain probability percentage, and UV index. If rain probability is above 40%, warn the player to have a backup plan or arrive early. If temperature is above 32°C, add a hydration tip. If UV index is above 6, remind them to apply sunscreen.
5. End with an encouraging line about making the most of the coaching time`;
} else if (sessionType === 'social game') {
  sessionTypeInstructions = `This is a SOCIAL GAME. Keep the tone relaxed and fun. Include:
1. A reminder of the session details
2. One fun focus to try during the game based on recent weak areas
3. A quick warm-up tip
4. Add a section with header exactly "Weather Forecast" — always include this section. Mention the temperature, rain probability percentage, and UV index. If rain probability is above 40%, warn the player to have a backup plan or arrive early. If temperature is above 32°C, add a hydration tip. If UV index is above 6, remind them to apply sunscreen.
5. End with a casual, fun motivating line`;
} else {
  sessionTypeInstructions = `This is a SOLO DRILL session. Include:
1. A reminder of the session details
2. Two specific drills targeting the weakest skill from recent sessions
3. A tip on how to structure the session
4. Add a section with header exactly "Weather Forecast" — always include this section. Mention the temperature, rain probability percentage, and UV index. If rain probability is above 40%, warn the player to have a backup plan or arrive early. If temperature is above 32°C, add a hydration tip. If UV index is above 6, remind them to apply sunscreen.
5. End with an encouraging line about the grind paying off`;
}

const prompt = `You are a personal tennis coach assistant sending a pre-session brief the night before a session.

Upcoming session: ${eventTitle} at ${eventLocation} on ${eventDate} at ${eventTime}

Last 3 sessions summary (most recent: ${lastDate} - ${lastType}):
- Common things that went well: ${commonWentWell}
- Common areas to improve: ${commonImprove}
- Notes: ${commonNotes}
- Avg skill ratings: Serve ${serve}/5, Return ${returnRating}/5, Forehand ${forehand}/5, Backhand ${backhand}/5, Volley ${volley}/5, Footwork ${footwork}/5, Focus ${focus}/5

${lastMatchContext}

${weatherContext}

${sessionTypeInstructions}

Use **text** for bold headers. Keep it concise, personal and energetic. Do not use generic filler phrases.`;

const cleanPrompt = prompt.replace(/[\u0000-\u001F\u007F]/g, ' ').replace(/\\/g, '\\\\').replace(/"/g, '\\"');

return [{
  json: {
    prompt: cleanPrompt,
    eventTitle,
    eventDate,
    eventTime,
    eventLocation,
    sessionType,
    chatId: '1328995037'
  }
}];

