parameters.jsCode:
const staticData = $getWorkflowStaticData('global');
const chatId = $input.all()[0].json.chatId;
const answer = $input.all()[0].json.originalData.callback_query.data;
staticData[chatId].data.return_rating = answer === 'na' ? null : parseInt(answer);
staticData[chatId].state = 'ask_forehand';
return [{ json: { chatId, nextState: 'ask_forehand' } }];

const data = $('Handle Confirm Save').first().json.data;
const sessionId = $('Handle Confirm Save').first().json.sessionId;
const chatId = $('Handle Confirm Save').first().json.chatId;

// Find strongest and weakest skill
const skills = {
  Serve: data.serve,
  Return: data.return_rating,
  Forehand: data.forehand,
  Backhand: data.backhand,
  Volley: data.volley,
  Footwork: data.footwork,
  Focus: data.mental_focus
};

const validSkills = Object.entries(skills).filter(([k, v]) => v !== null && v !== undefined);
const strongest = validSkills.length ? validSkills.reduce((a, b) => a[1] > b[1] ? a : b) : null;
const weakest = validSkills.length ? validSkills.reduce((a, b) => a[1] < b[1] ? a : b) : null;

const sessionType = data.session_type ? data.session_type.split('_').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ') : 'Session';

// Build match context
let matchContext = '';
if (data.session_type === 'match') {
  matchContext = `Match result: ${data.result || 'N/A'} vs ${data.opponent_name || 'Unknown'} (${data.opponent_level || 'N/A'}) — Score: ${data.score || 'N/A'}. Tactical focus: ${data.tactical_focus || 'N/A'}.`;
}

const prompt = `You are a personal tennis coach assistant. Write a short post-session message for your player who just finished a tennis session.

Session data:
- Type: ${sessionType}
- Duration: ${data.duration_min || 'N/A'} minutes
- Location: ${data.location || 'N/A'}
- Strongest skill today: ${strongest ? strongest[0] + ' (' + strongest[1] + '/5)' : 'N/A'}
- Weakest skill today: ${weakest ? weakest[0] + ' (' + weakest[1] + '/5)' : 'N/A'}
- Energy before: ${data.energy_before || 'N/A'} | Energy after: ${data.energy_after || 'N/A'}
- Mood: ${data.mood || 'N/A'}
- Went well: ${data.went_well || 'N/A'}
- Improve: ${data.improve || 'N/A'}
${matchContext}

Write a 4-5 line post-session message that:
1. Acknowledges the session (type, duration, location)
2. Highlights the strongest skill with a positive note
3. Flags the weakest skill with one specific actionable tip
4. If match — add one line about the result and tactical reflection
5. End with an encouraging line based on mood and energy — no label, feels natural like a coach talking

Use **text** for bold. Keep it concise, warm and specific. No generic filler phrases.`;

return [{
  json: {
    prompt,
    chatId
  }
}];

const items = $('Query Progress').all();
const sessions = items.map(i => i.json);

// Deduplicate
const seen = new Set();
const unique = sessions.filter(s => {
  if (seen.has(s.session_date + s.session_type)) return false;
  seen.add(s.session_date + s.session_type);
  return true;
});

// Skill trends over time
const skillTrends = unique.map(s => ({
  date: s.session_date,
  serve: s.serve,
  forehand: s.forehand,
  backhand: s.backhand,
  volley: s.volley,
  footwork: s.footwork,
  focus: s.mental_focus,
  return_rating: s.return_rating
}));

// Duration trend
const durationTrend = unique
  .filter(s => s.duration_min)
  .map(s => ({
    date: s.session_date,
    duration: s.duration_min
  }));

// Energy by session type
const energyByType = {};
unique.forEach(s => {
  if (!energyByType[s.session_type]) {
    energyByType[s.session_type] = { before: [], after: [] };
  }
  if (s.energy_before) energyByType[s.session_type].before.push(parseFloat(s.energy_before));
  if (s.energy_after) energyByType[s.session_type].after.push(parseFloat(s.energy_after));
});

const energySummary = Object.entries(energyByType).map(([type, data]) => ({
  type,
  avg_before: data.before.length ? (data.before.reduce((a, b) => a + b, 0) / data.before.length).toFixed(1) : null,
  avg_after: data.after.length ? (data.after.reduce((a, b) => a + b, 0) / data.after.length).toFixed(1) : null
}));

// First 30d vs last 30d comparison
const sorted = [...unique].sort((a, b) => new Date(a.session_date) - new Date(b.session_date));
const first30 = sorted.slice(0, 30);
const last30 = sorted.slice(-30);

const skills = ['serve', 'forehand', 'backhand', 'volley', 'footwork', 'mental_focus', 'return_rating'];
const avg = (arr, field) => {
  const vals = arr.map(s => parseFloat(s[field])).filter(v => !isNaN(v));
  return vals.length ? (vals.reduce((a, b) => a + b, 0) / vals.length).toFixed(1) : null;
};

const trajectory = skills.map(skill => ({
  skill,
  first30: avg(first30, skill),
  last30: avg(last30, skill)
}));

return [{
  json: {
    skill_trends: skillTrends,
    duration_trend: durationTrend,
    energy_by_type: energySummary,
    trajectory
  }
}];

const overview = $('Query Overview').first().json;
const locationStreak = $('Query Location & Streak').first().json;

return [{
  json: {
    total_sessions: overview.total_sessions,
    total_minutes: overview.total_minutes,
    total_matches: overview.total_matches,
    total_wins: overview.total_wins,
    total_losses: overview.total_losses,
    session_types: {
      match: overview.total_matches,
      coaching: overview.total_coaching,
      social_game: overview.total_social,
      solo_drill: overview.total_drill
    },
    skill_averages: {
      serve: parseFloat(overview.avg_serve || 0).toFixed(1),
      forehand: parseFloat(overview.avg_forehand || 0).toFixed(1),
      backhand: parseFloat(overview.avg_backhand || 0).toFixed(1),
      volley: parseFloat(overview.avg_volley || 0).toFixed(1),
      footwork: parseFloat(overview.avg_footwork || 0).toFixed(1),
      focus: parseFloat(overview.avg_focus || 0).toFixed(1),
      return_rating: parseFloat(overview.avg_return || 0).toFixed(1)
    },
    top_location: locationStreak.top_location,
    current_streak: locationStreak.current_streak
  }
}];

const items = $('Query Matches').all();
const matches = items.map(i => i.json);

// Deduplicate
const seen = new Set();
const unique = matches.filter(m => {
  if (seen.has(m.match_id)) return false;
  seen.add(m.match_id);
  return true;
});

// Overall win/loss
const totalMatches = unique.length;
const wins = unique.filter(m => m.result === 'win').length;
const losses = unique.filter(m => m.result === 'loss').length;
const winRate = totalMatches ? ((wins / totalMatches) * 100).toFixed(0) : 0;

// Win/loss by opponent level
const byLevel = ['higher', 'similar', 'lower'].map(level => {
  const levelMatches = unique.filter(m => m.opponent_level === level);
  const levelWins = levelMatches.filter(m => m.result === 'win').length;
  return {
    level,
    matches: levelMatches.length,
    wins: levelWins,
    losses: levelMatches.length - levelWins,
    win_rate: levelMatches.length ? ((levelWins / levelMatches.length) * 100).toFixed(0) : 0
  };
});

// Head-to-head record
const headToHead = {};
unique.forEach(m => {
  const opponent = m.opponent_name || 'Unknown';
  if (!headToHead[opponent]) {
    headToHead[opponent] = { wins: 0, losses: 0, matches: [] };
  }
  if (m.result === 'win') headToHead[opponent].wins++;
  else headToHead[opponent].losses++;
  headToHead[opponent].matches.push({
    date: m.session_date,
    result: m.result,
    score: m.score
  });
});

const headToHeadList = Object.entries(headToHead).map(([opponent, data]) => ({
  opponent,
  wins: data.wins,
  losses: data.losses,
  total: data.wins + data.losses,
  matches: data.matches
})).sort((a, b) => b.total - a.total);

// Tactical focus raw list for Gemini grouping
const tactics = unique
  .filter(m => m.tactical_focus)
  .map(m => ({
    tactic: m.tactical_focus,
    result: m.result
  }));

// Recent matches
const recentMatches = unique.slice(0, 10).map(m => ({
  date: m.session_date,
  opponent: m.opponent_name,
  opponent_level: m.opponent_level,
  result: m.result,
  score: m.score,
  tactical_focus: m.tactical_focus,
  location: m.location
}));

return [{
  json: {
    total_matches: totalMatches,
    wins,
    losses,
    win_rate: winRate,
    by_level: byLevel,
    head_to_head: headToHeadList,
    tactics_raw: tactics,
    recent_matches: recentMatches
  }
}];

const activityItems = $('Query Activity').all();
const sessions = activityItems.map(i => i.json);

const seen = new Set();
const unique = sessions.filter(s => {
  if (seen.has(s.session_date + s.session_type)) return false;
  seen.add(s.session_date + s.session_type);
  return true;
});

const heatmap = {};
unique.forEach(s => {
  const date = s.session_date;
  if (!heatmap[date]) heatmap[date] = 0;
  heatmap[date]++;
});

const heatmapData = Object.entries(heatmap).map(([date, count]) => ({ date, count }));

const coachingSessions = unique
  .filter(s => s.session_type === 'coaching')
  .map(s => ({
    date: s.session_date,
    location: s.location || null,
    drills_focus: s.drills_focus || null,
    duration: s.duration_min || null
  }));

const calendarData = $('Query Google Calendar (Dashboard)').first().json;
const upcomingSessions = (calendarData.items || [])
  .filter(e => e.summary && e.summary.includes('🎾'))
  .map(e => {
    const start = new Date(e.start.dateTime || e.start.date);
    return {
      title: e.summary,
      date: start.toLocaleDateString('en-MY', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Asia/Kuala_Lumpur' }),
      time: e.start.dateTime ? start.toLocaleTimeString('en-MY', { hour: '2-digit', minute: '2-digit', timeZone: 'Asia/Kuala_Lumpur' }) : 'All day',
      location: e.location || null
    };
  });

return [{
  json: {
    heatmap: heatmapData,
    coaching_sessions: coachingSessions,
    upcoming_sessions: upcomingSessions
  }
}];

const staticData = $getWorkflowStaticData('global');
const chatId = $('Get Session State').first().json.chatId;
staticData[chatId].state = 'idle';
return [{ json: { chatId } }];

