const items = $('Query Insights Text').all();
const geminiRaw = $('Call Gemini (Insights Summary)').first().json;

let strengths = [];
let priorities = [];

try {
  const text = geminiRaw.candidates[0].content.parts[0].text.trim();
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed = JSON.parse(cleaned);
  strengths = parsed.strengths || [];
  priorities = parsed.priorities || [];
} catch(e) {
  strengths = [];
  priorities = [];
}

return [{
  json: { strengths, priorities, session_count: items.length }
}];

const event = $('IF Session Tomorrow?').first().json;

if (!event.summary || !event.summary.includes('🎾')) {
  return [];
}

return [{ json: event }];
